#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int maxVal = N; // Ai <= N
        int *freq = (int*)calloc(maxVal+2, sizeof(int));
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            freq[x]++;
        }
        int maxSingle = 0, maxPair = 0;
        for(int v=0; v<=maxVal; ++v){
            if(freq[v] > maxSingle) maxSingle = freq[v];
        }
        for(int e=0; e<=maxVal; e+=2){
            int cur = freq[e] + freq[e+1];
            if(cur > maxPair) maxPair = cur;
        }
        int best = maxSingle > maxPair ? maxSingle : maxPair;
        printf("%d\n", N - best);
        free(freq);
    }
    return 0;
}

